insert into public.equipment (id, name, category, owner, status, summary, specs, image_url, image_query, source_urls, updated_at) values
  ('moonfall-drones', 'MoonFall Drones', 'science', 'NASA', 'in-development', 'Small autonomous lunar drones planned to scout steep and shadowed South Pole terrain for Moon Base site knowledge.', '[{"label":"Role","value":"Terrain scouting"},{"label":"Quantity","value":"Four drones"},{"label":"Phase","value":"Phase One"}]'::jsonb, null, 'NASA lunar hopper drone Moon South Pole', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('radioisotope-heating-units', 'Radioisotope Heating Units', 'power', 'NASA', 'planned', 'Thermal survival units that use radioisotope heat to keep lunar instruments and systems warm in extreme cold.', '[{"label":"Role","value":"Thermal survival"},{"label":"Use case","value":"Lunar night and shadowed regions"},{"label":"Phase","value":"Phase One"}]'::jsonb, null, 'NASA radioisotope heater unit lunar surface', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('lunar-relay-satellites', 'Relay and Observation Satellites', 'communications', 'NASA / Partners', 'planned', 'Orbital communications and observation assets for lunar relay, positioning, navigation, and surface support.', '[{"label":"Role","value":"Relay and observation"},{"label":"Network","value":"LunaNet-compatible services"},{"label":"Phase","value":"Phase One"}]'::jsonb, null, 'NASA lunar relay satellite LunaNet', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('site-logistics-rovers', 'Site Logistics Rovers', 'rover', 'NASA / Commercial providers', 'planned', 'Robotic rovers for site preparation, regolith handling, cargo movement, and surface logistics.', '[{"label":"Role","value":"Site preparation and cargo mobility"},{"label":"Operations","value":"Excavation, compaction, transport"},{"label":"Phase","value":"Phase Two"}]'::jsonb, null, 'NASA lunar logistics rover regolith excavation', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('nuclear-surface-power', 'Nuclear Surface Power', 'power', 'NASA / DOE', 'planned', 'Radioisotope and future nuclear power demonstrations for resilient lunar surface energy.', '[{"label":"Role","value":"Night and shadowed-region power"},{"label":"Capability","value":"Radioisotope power demonstration"},{"label":"Phase","value":"Phase Two"}]'::jsonb, null, 'NASA lunar nuclear surface power', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('solar-power-augmentation', 'Solar Power Augmentation', 'power', 'NASA / Partners', 'planned', 'Deployable solar arrays, batteries, and power distribution demonstrations for larger lunar surface infrastructure.', '[{"label":"Role","value":"Power generation and storage"},{"label":"Systems","value":"Solar arrays, batteries, hubs"},{"label":"Phase","value":"Phase Two"}]'::jsonb, null, 'NASA lunar surface solar array battery power hub', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('surface-communications', 'Surface Communications Systems', 'communications', 'NASA / Partners', 'planned', 'Dedicated surface-to-orbit stations and local surface communication nodes for a larger Moon Base network.', '[{"label":"Role","value":"Surface networking"},{"label":"Architecture","value":"Surface-to-orbit and local nodes"},{"label":"Phase","value":"Phase Two"}]'::jsonb, null, 'NASA lunar surface communications station LunaNet', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('isru-demo', 'ISRU Systems', 'science', 'NASA / Partners', 'planned', 'In-situ resource utilization systems for extracting oxygen, water, and hydrogen and processing lunar regolith.', '[{"label":"Role","value":"Resource extraction and processing"},{"label":"Materials","value":"Oxygen, water, hydrogen, regolith"},{"label":"Phase","value":"Phase Three"}]'::jsonb, null, 'NASA lunar ISRU oxygen water regolith processing', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('cargo-return-system', 'Cargo Return System', 'science', 'NASA / Commercial providers', 'planned', 'Uncrewed return capability for lunar samples, research payloads, and hardware from the surface back to Earth.', '[{"label":"Role","value":"Surface-to-Earth cargo return"},{"label":"Capacity","value":"Up to 500 kg target class"},{"label":"Phase","value":"Phase Three"}]'::jsonb, null, 'NASA lunar cargo return vehicle sample return', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('lunar-logistics-network', 'Lunar Logistics Network', 'science', 'NASA / Partners', 'planned', 'Sustained delivery, storage, movement, and return logistics for a continuously operating lunar base.', '[{"label":"Role","value":"Sustained surface logistics"},{"label":"Scope","value":"Delivery, storage, mobility, return"},{"label":"Phase","value":"Phase Three"}]'::jsonb, null, 'NASA lunar base logistics cargo delivery', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now())
insert into public.missions (id, title, subtitle, program_ids, phase_id, status, date_label, date_precision, summary, objectives, landing_region, source_urls, updated_at) values
  ('moon-base-i', 'Moon Base I', 'Blue Moon Mark 1 / Endurance', '["moon-base","clps","surface-systems"]'::jsonb, 'phase-one', 'in-development', '2028', 'year', 'Blue Origin''s Blue Moon Mark 1 lander will deliver NASA science and technology payloads while demonstrating capabilities for sustained lunar surface operations.', '["Land near Shackleton Connecting Ridge","Demonstrate precision landing and autonomous guidance","Carry plume-surface cameras and a laser retroreflective array"]'::jsonb, 'Shackleton Connecting Ridge', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('moon-base-ii', 'Moon Base II', 'Astrobotic Griffin-1', '["moon-base","clps","surface-systems"]'::jsonb, 'phase-one', 'planned', 'Now-2029', 'range', 'Astrobotic''s Griffin Mission One will demonstrate commercial lunar landing and mobility capabilities while delivering NASA and partner payloads.', '["Target Nobile Crater near the lunar South Pole","Deliver Astrolab''s FLIP rover demonstration","Carry NASA, ESA, Astrobotic, and commercial payloads"]'::jsonb, 'Nobile Crater', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('moon-base-iii', 'Moon Base III', 'Intuitive Machines IM-3 / Nova-C', '["moon-base","clps","surface-systems"]'::jsonb, 'phase-one', 'planned', 'Now-2029', 'range', 'Intuitive Machines'' IM-3 mission will deliver NASA science and technology payloads to Reiner Gamma using the Nova-C lander Trinity.', '["Deliver Lunar Vertex science payloads","Investigate magnetic anomalies and lunar swirls","Carry international partner payloads"]'::jsonb, 'Reiner Gamma', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('moonfall-drones', 'MoonFall Drones', 'South Pole scouting drones', '["moon-base","surface-systems"]'::jsonb, 'phase-one', 'in-development', '2028', 'year', 'NASA plans to deploy four highly mobile MoonFall drones to scout steep terrain and permanently shadowed regions near the lunar South Pole.', '["Survey terrain that rovers cannot easily access","Operate independently over roughly one lunar day","Collect imagery and site data for future surface operations"]'::jsonb, 'Lunar South Pole region', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('lunar-terrain-vehicles-phase-one', 'Lunar Terrain Vehicles', 'Phase One surface mobility', '["moon-base","surface-systems","clps"]'::jsonb, 'phase-one', 'in-development', '2028', 'year', 'NASA plans to begin deploying crewed and uncrewed Lunar Terrain Vehicles to establish early surface mobility for the Moon Base.', '["Deploy crewed and uncrewed mobility systems","Support teleoperation and early exploration","Prepare longer-range surface traverses"]'::jsonb, 'Lunar South Pole region', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('radioisotope-heating-units', 'Radioisotope Heating Units', 'Lunar night survival demo', '["moon-base","surface-systems"]'::jsonb, 'phase-one', 'planned', 'Now-2029', 'range', 'NASA plans to demonstrate radioisotope heating technologies that can keep instruments, batteries, and mechanisms warm in shadowed lunar environments.', '["Support survival through long lunar nights","Enable operations in cold, shadowed regions","Mature thermal systems for sustained surface missions"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('lunar-relay-observation-satellites', 'Communications and Observation Satellites', 'Initial lunar relay assets', '["moon-base","surface-systems"]'::jsonb, 'phase-one', 'planned', 'Now-2029', 'range', 'NASA anticipates deploying orbital relay and observation assets to expand communications, positioning, and navigation support for lunar surface operations.', '["Improve Earth-to-surface communications","Demonstrate early LunaNet interoperability","Support growing lunar surface operations"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('viper-moon-base', 'VIPER', 'Volatiles rover delivery', '["moon-base","clps","surface-systems"]'::jsonb, 'phase-one', 'planned', 'Late 2027', 'half', 'NASA''s VIPER rover is planned for delivery to the lunar surface to search for water ice and other volatiles near the Moon''s South Pole.', '["Map water ice and other volatile resources","Use a one-meter drill to analyze lunar soil","Inform long-term Moon Base resource strategy"]'::jsonb, 'Lunar South Pole region', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('pressurized-rover-phase-two', 'Pressurized Rover', 'JAXA mobile habitat rover', '["moon-base","surface-systems"]'::jsonb, 'phase-two', 'planned', '2029-2032', 'range', 'JAXA''s pressurized rover is expected to give astronauts a mobile habitat and laboratory for longer traverses across the lunar South Pole region.', '["Support two astronauts in a shirt-sleeve environment","Enable traverses lasting up to 30 days","Extend science operations beyond fixed landing sites"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('site-logistics-rovers-phase-two', 'Site Preparation and Logistics Rovers', 'Phase Two robotic surface logistics', '["moon-base","surface-systems"]'::jsonb, 'phase-two', 'planned', '2029-2032', 'range', 'NASA plans to deploy site preparation and logistics rovers for regolith handling, soil compaction, cargo transport, and early surface logistics.', '["Prepare and maintain surface work sites","Move cargo and logistics across the base area","Support excavation, compaction, and transport operations"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('nuclear-surface-power-demo', 'Nuclear Surface Power Capability', 'RTG and power process demo', '["moon-base","surface-systems"]'::jsonb, 'phase-two', 'planned', '2029-2032', 'range', 'Phase Two includes nuclear surface power demonstrations using radioisotope power systems to inform future large-scale lunar power systems.', '["Demonstrate radioisotope power systems","Support night survival and shadowed-region operations","Mature processes for future large-scale nuclear power"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('solar-power-augmentation', 'Solar Power Augmentation', 'Surface energy storage and distribution', '["moon-base","surface-systems"]'::jsonb, 'phase-two', 'planned', '2029-2032', 'range', 'NASA plans to test solar array deployment, battery technologies, and surface power distribution for more capable lunar power infrastructure.', '["Demonstrate deployable solar arrays","Test batteries and surface power hubs","Inform high-capacity power generation and storage"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('surface-communications-systems', 'Surface Communications Systems', 'Lunar surface network expansion', '["moon-base","surface-systems"]'::jsonb, 'phase-two', 'planned', '2029-2032', 'range', 'NASA plans to demonstrate dedicated surface-to-orbit communications stations and local surface communications nodes.', '["Increase surface data throughput","Provide local communications coverage","Create a more resilient lunar communications architecture"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('lunar-habitats-phase-three', 'Habitats', 'Sustained surface habitation', '["moon-base","surface-systems"]'::jsonb, 'phase-three', 'planned', '2032+', 'range', 'NASA plans to expand from early short-duration habitation toward larger modules with improved life support, airlocks, and aggregation nodes.', '["Expand crew living and operations volume","Add airlocks and interconnected habitat nodes","Support longer-duration human surface presence"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('isru-capability', 'In-situ Resource Utilization', 'Lunar resource processing', '["moon-base","surface-systems"]'::jsonb, 'phase-three', 'planned', '2032+', 'range', 'NASA plans to mature ISRU systems that can use lunar resources and reduce the cost and risk of long-duration surface operations.', '["Extract oxygen, water, and hydrogen from lunar material","Explore construction with regolith processing","Reduce launch mass for sustained lunar operations"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('uncrewed-cargo-return', 'Uncrewed Cargo Return', 'Sample and payload return capability', '["moon-base","surface-systems"]'::jsonb, 'phase-three', 'planned', '2032+', 'range', 'NASA plans to implement cargo return capabilities from the lunar surface to Earth for science samples, research payloads, and critical hardware.', '["Return up to 500 kilograms of material","Move science samples and payloads back to Earth","Support evaluation of lunar surface hardware"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now()),
  ('lunar-logistics-network', 'Logistics', 'Sustained Moon Base supply network', '["moon-base","surface-systems"]'::jsonb, 'phase-three', 'planned', '2032+', 'range', 'NASA plans to expand end-to-end logistics so habitats, power systems, science sites, and crews can be sustained year-round.', '["Increase delivered logistics capacity","Support crews, habitats, and surface systems","Enable sustained lunar base operations"]'::jsonb, null, '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb, now())
