  ('solar-power-augmentation', 'nasa-moon-base-phases', 'solar-power-phase-two-window', 'Solar power augmentation demo window', '2029-01-01T00:00:00Z', '2029-2032', 'range', 'planned', 'Solar array, battery, and power distribution demos prepare for larger permanent infrastructure.', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb),
  ('surface-communications-systems', 'nasa-moon-base-phases', 'surface-comms-phase-two-window', 'Surface communications expansion window', '2029-01-01T00:00:00Z', '2029-2032', 'range', 'planned', 'Surface-to-orbit stations and local nodes provide greater connectivity across the South Pole region.', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb),
  ('lunar-habitats-phase-three', 'nasa-moon-base-phases', 'habitats-phase-three-window', 'Expanded habitat infrastructure window', '2032-01-01T00:00:00Z', '2032+', 'range', 'planned', 'Larger habitats, airlocks, and aggregation nodes support sustained human surface operations.', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb),
  ('isru-capability', 'nasa-moon-base-phases', 'isru-phase-three-window', 'ISRU sustained capability window', '2032-01-01T00:00:00Z', '2032+', 'range', 'planned', 'Resource processing efforts mature toward sustained use of lunar oxygen, water, hydrogen, and regolith.', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb),
  ('uncrewed-cargo-return', 'nasa-moon-base-phases', 'cargo-return-phase-three-window', 'Uncrewed cargo return capability window', '2032-01-01T00:00:00Z', '2032+', 'range', 'planned', 'Cargo return systems support return of scientific samples, research payloads, and critical hardware.', '[{"label":"NASA Moon Base Phases","url":"https://www.nasa.gov/moonbase-phases/","confidence":"official"}]'::jsonb),
