update public.phases
set
  summary = 'Learn, test, and build through robotic missions, early surface demonstrations, and technology validation near the lunar South Pole.',
  focus = '["Moon Base I-III","MoonFall drones","LTVs","VIPER","power and communications demos"]'::jsonb,
  updated_at = now()
where id = 'phase-one';

update public.phases
set
  summary = 'Early habitation and logistics phase with expanded power, pressurized mobility, site preparation, and surface communications.',
  focus = '["pressurized rover","site logistics","nuclear power","solar augmentation","surface communications"]'::jsonb,
  updated_at = now()
where id = 'phase-two';

update public.phases
set
  summary = 'Scale toward sustained human presence with larger habitats, ISRU, cargo return, logistics, and continuous surface activity.',
  focus = '["habitats","ISRU","cargo return","sustained logistics","continuous surface activity"]'::jsonb,
  updated_at = now()
where id = 'phase-three';

on conflict (id) do update set
  name = excluded.name,
  category = excluded.category,
  owner = excluded.owner,
  status = excluded.status,
  summary = excluded.summary,
  specs = excluded.specs,
  image_query = excluded.image_query,
  source_urls = excluded.source_urls,
  updated_at = now();

on conflict (id) do update set
  title = excluded.title,
  subtitle = excluded.subtitle,
  program_ids = excluded.program_ids,
  phase_id = excluded.phase_id,
  status = excluded.status,
  date_label = excluded.date_label,
  date_precision = excluded.date_precision,
  summary = excluded.summary,
  objectives = excluded.objectives,
  landing_region = excluded.landing_region,
  source_urls = excluded.source_urls,
  updated_at = now();

on conflict do nothing;

on conflict (external_source, external_id) do update set
  mission_id = excluded.mission_id,
  title = excluded.title,
  starts_at = excluded.starts_at,
  date_label = excluded.date_label,
  date_precision = excluded.date_precision,
  status = excluded.status,
  summary = excluded.summary,
  source_urls = excluded.source_urls,
  updated_at = now();
